125	------------------------------------------------------------------------------
126	-- Package Body
127	------------------------------------------------------------------------------
128	package body psi_common_math_pkg is
129	
130	  -- *************************************************************************
131	  -- Helpers
132	  -- *************************************************************************
133	  -- Coun the number of elements in a array string (separated by ",")
134	  function count_array_str_elements(input : string) return natural is
135	    variable count : natural := 1;
136	    variable idx   : integer := input'low;
137	  begin
138	    while idx <= input'high loop
139	      if input(idx) = ',' then
140	        count := count + 1;
141	      end if;
142	      idx := idx + 1;
143	    end loop;
144	    return count;
145	  end function;
146	
147	  -- *************************************************************************
148	  -- Public Functions
149	  -- *************************************************************************
150	
151	  -- *** Log2 integer ***
152	  function log2(arg : in natural) return natural is
153	    variable v : natural := arg;
154	    variable r : natural := 0;
155	  begin
156	    while v > 1 loop
157	      v := v / 2;
158	      r := r + 1;
159	    end loop;
160	    return r;
161	  end function;
162	
163	  -- *** Log2Ceil integer ***
164	  function log2ceil(arg : in natural) return natural is
165	  begin
166	    if arg = 0 then
167	      return 0;
168	    end if;
169	    return log2(arg * 2 - 1);
170	  end function;
171	
172	  -- *** Log2Ceil real ***
173	  function log2ceil(arg : in real) return natural is
174	    variable v : real    := arg;
175	    variable r : natural := 0;
176	  begin
177	    while v > 1.0 loop
178	      v := v / 2.0;
179	      r := r + 1;
180	    end loop;
181	    return r;
182	  end function;
183	
184	  -- *** isLog2 ***
185	  function isLog2(arg : in natural) return boolean is
186	  begin
187	    if log2(arg) = log2ceil(arg) then
188	      return true;
189	    else
190	      return false;
191	    end if;
192	  end function;
193	
194	  -- *** Max ***
195	  function max(a : in integer;
196	               b : in integer) return integer is
197	  begin
198	    if a > b then
199	      return a;
200	    else
201	      return b;
202	    end if;
203	  end function;
204	
205	  function max(a : in real;
206	               b : in real) return real is
207	  begin
208	    if a > b then
209	      return a;
210	    else
211	      return b;
212	    end if;
213	  end function;
214	
215	  -- *** Min ***
216	  function min(a : in integer;
217	               b : in integer) return integer is
218	  begin
219	    if a > b then
220	      return b;
221	    else
222	      return a;
223	    end if;
224	  end function;
225	
226	  function min(a : in real;
227	               b : in real) return real is
228	  begin
229	    if a > b then
230	      return b;
231	    else
232	      return a;
233	    end if;
234	  end function;
235	
236	  -- *** Choose (std_logic) ***
237	  function choose(s : in boolean;
238	                  t : in std_logic;
239	                  f : in std_logic) return std_logic is
240	  begin
241	    if s then
242	      return t;
243	    else
244	      return f;
245	    end if;
246	  end function;
247	
248	  -- *** Choose (std_logic_vector) ***
249	  function choose(s : in boolean;
250	                  t : in std_logic_vector;
251	                  f : in std_logic_vector) return std_logic_vector is
252	  begin
253	    if s then
254	      return t;
255	    else
256	      return f;
257	    end if;
258	  end function;
259	
260	  -- *** Choose (integer) ***
261	  function choose(s : in boolean;
262	                  t : in integer;
263	                  f : in integer) return integer is
264	  begin
265	    if s then
266	      return t;
267	    else
268	      return f;
269	    end if;
270	  end function;
271	
272	  -- *** Choose (string) ***
273	  function choose(s : in boolean;
274	                  t : in string;
275	                  f : in string) return string is
276	  begin
277	    if s then
278	      return t;
279	    else
280	      return f;
281	    end if;
282	  end function;
283	
284	  -- *** Choose (real) ***
285	  function choose(s : in boolean;
286	                  t : in real;
287	                  f : in real) return real is
288	  begin
289	    if s then
290	      return t;
291	    else
292	      return f;
293	    end if;
294	  end function;
295	
296	  -- *** Choose (unsigned) ***
297	  function choose(s : in boolean;
298	                  t : in unsigned;
299	                  f : in unsigned) return unsigned is
300	  begin
301	    if s then
302	      return t;
303	    else
