328	      return f;
329	    end if;
330	  end function;
331	
332	  -- *** count (integer) ***
333	  function count(a : in t_ainteger;
334	                 v : in integer) return integer is
335	    variable cnt_v : integer := 0;
336	  begin
337	    for idx in a'low to a'high loop
338	      if a(idx) = v then
339	        cnt_v := cnt_v + 1;
340	      end if;
341	    end loop;
342	    return cnt_v;
343	  end function;
344	
