6	
7	------------------------------------------------------------------------------
8	-- Description
9	------------------------------------------------------------------------------
10	-- This is a delay element. It is either emplemented in BRAM or SRL. The output
11	-- is always a fabric register for improved timing.
12	
13	
14	library ieee;
15	use ieee.std_logic_1164.all;
16	use ieee.numeric_std.all;
17	
18	use work.psi_common_math_pkg.all;
19	--@formatter:off
20	entity psi_common_delay is
21	  generic(width_g          : positive := 16;                               -- vector length
22	          delay_g          : positive := 10;                               -- Delay
23	          resource_g       : string   := "AUTO";                           -- AUTO, SRL or BRAM
24	          bram_threshold_g : positive := 128;                              -- Number of delay taps to start using BRAM from (if Resource_g = AUTO)
25	          rst_state_g      : boolean  := True;                             -- True = '0' is outputted after reset, '1' after reset the existing state is outputted
26	          rst_pol_g        : std_logic:='1';                               -- reset polarity
27	          ram_behavior_g   : string   := "RBW" );                          -- "RBW" = read-before-write, "WBR" = write-before-read
28	  port(   clk_i            : in  std_logic;                                -- system clock
29	          rst_i            : in  std_logic;                                -- system reset
30	          dat_i            : in  std_logic_vector(width_g - 1 downto 0);   -- data input
31	          vld_i            : in  std_logic;                                -- valid input
32	          dat_o            : out std_logic_vector((width_g - 1) downto 0); -- data output
33	          vld_o            : out std_logic);                               -- valid output
34	end entity;
35	--@formatter:on
36	architecture rtl of psi_common_delay is
37	  signal MemOut           : std_logic_vector(width_g - 1 downto 0);
38	  constant MemTaps_c      : natural := delay_g - 1;
39	  signal RstStateCnt      : integer range 0 to delay_g - 1;
40	  attribute shreg_extract : string;
41	  attribute srl_style     : string;
42	  constant ground_c       : std_logic:='0';
43	begin
44	
45	  -- *** Assertions ***
46	  assert resource_g = "AUTO" or resource_g = "SRL" or resource_g = "BRAM" report "###ERROR###: psi_common_delay: Unknown resource_g - " & resource_g severity error;
47	  assert resource_g /= "BRAM" or delay_g >= 3 report "###ERROR###: psi_common_delay: delay_g >= 3 required for resource_g=BRAM" severity error;
48	  assert bram_threshold_g > 3 report "###ERROR###: psi_common_delay: bram_threshold_g must be > 3" severity error;
49	
50	  -- *** SRL ***
51	  g_srl : if (delay_g > 1) and ((resource_g = "SRL") or ((resource_g = "AUTO") and (delay_g < bram_threshold_g))) generate
52	    type Srl_t is array (0 to MemTaps_c - 1) of std_logic_vector(width_g - 1 downto 0);
53	    signal SrlSig : Srl_t := (others => (others => '0'));
54	    attribute shreg_extract of SrlSig : signal is "true";
55	    attribute srl_style of SrlSig : signal is "srl";
56	  begin
57	    p_srl : process(clk_i)
58	    begin
59	      if rising_edge(clk_i) then
60	        if vld_i = '1' then
61	          SrlSig(0)                <= dat_i;
62	          SrlSig(1 to SrlSig'high) <= SrlSig(0 to SrlSig'high - 1);
63	        end if;
64	      end if;
65	    end process;
66	    MemOut <= SrlSig(SrlSig'high);
67	  end generate;
68	
69	  -- *** BRAM ***
70	  g_bram : if (delay_g > 1) and ((resource_g = "BRAM") or ((resource_g = "AUTO") and (delay_g >= bram_threshold_g))) generate
71	    signal RdAddr, WrAddr : std_logic_vector(log2ceil(MemTaps_c) - 1 downto 0) := (others => '0');
72	  begin
73	    -- address control process
74	    p_bram : process(clk_i)
75	    begin
76	      if rising_edge(clk_i) then
77	        if rst_i = rst_pol_g then
78	          WrAddr <= std_logic_vector(to_unsigned(MemTaps_c - 1, WrAddr'length));
79	          RdAddr <= (others => '0');
80	        elsif vld_i = '1' then
81	          -- write address
82	          if unsigned(WrAddr) = MemTaps_c - 1 then
83	            WrAddr <= (others => '0');
84	          else
85	            WrAddr <= std_logic_vector(unsigned(WrAddr) + 1);
86	          end if;
87	          -- read address
88	          if unsigned(RdAddr) = MemTaps_c - 1 then
89	            RdAddr <= (others => '0');
90	          else
91	            RdAddr <= std_logic_vector(unsigned(RdAddr) + 1);
92	          end if;
93	        end if;
94	      end if;
95	    end process;
96	
97	    -- memory instantiation
98	    i_bram : entity work.psi_common_sdp_ram
99	      generic map(
100	        depth_g        => MemTaps_c,
101	        width_g        => width_g,
102	        is_async_g     => false,
103	        ram_style_g    => "auto",
104	        ram_behavior_g => ram_behavior_g
105	      )
106	      port map(
107	        wr_clk_i  => clk_i,    
108	        wr_addr_i => WrAddr,
109	        wr_i      => vld_i,
110	        wr_dat_i  => dat_i,
111	        rd_clk_i  => ground_c,
112	        rd_addr_i => RdAddr,
113	        rd_i      => vld_i,
114	        rd_dat_o  => MemOut
115	      );
116	  end generate;
117	
118	  -- *** Single Stage ***
119	  g_single : if delay_g = 1 generate
120	    MemOut <= dat_i;
121	  end generate;
122	
123	  -- *** Output register ***
124	  p_outreg : process(clk_i)
125	  begin
126	    if rising_edge(clk_i) then
127	      if rst_i = rst_pol_g then
128	        dat_o       <= (others => '0');
